text:
Make room for negative priority values, e.g. `-100'.

  $ ps -axHOpri | awk 'NR == 1 || $2 ~ /^-/'
  $ top -SH | awk '$3 == "PRI" || $3 ~ /^-/'

--- c.diff begins here ---
--- usr.bin/top/machine.c~
+++ usr.bin/top/machine.c
@@ -607,9 +607,9 @@ fmt_pri(char *buf, int sz, struct kinfo_

 {
 #if OSMAJOR <= 4
-    return snprintf(buf, sz, "%3d", PP(pp, priority) - PZERO);
+    return snprintf(buf, sz, "%4d", PP(pp, priority) - PZERO);
 #else
-    return snprintf(buf, sz, "%3d", PP(pp, pri.pri_level) - PZERO);
+    return snprintf(buf, sz, "%4d", PP(pp, pri.pri_level) - PZERO);
 #endif
 }

@@ -626,7 +626,7 @@ fmt_nice(char *buf, int sz, struct kinfo
     switch (PRI_BASE(PP(pp, pri.pri_class))) {

     case PRI_ITHD:
-	retval = snprintf(buf, sz, "   -");
+	retval = snprintf(buf, sz, "%4s", "-");
 	break;

     case PRI_REALTIME:
@@ -658,7 +658,7 @@ fmt_nice(char *buf, int sz, struct kinfo

     case PRI_TIMESHARE:
 	if (PP(pp, flag) & P_KTHREAD) {
-	    retval = snprintf(buf, sz, "   -");
+	    retval = snprintf(buf, sz, "%4s", "-");
 	    break;
 	}

@@ -674,7 +674,7 @@ fmt_nice(char *buf, int sz, struct kinfo
 	break;

     default:
-	retval = snprintf(buf, sz, "?");
+	retval = snprintf(buf, sz, "%4s", "?");
 	break;
     }

@@ -959,7 +959,7 @@ struct proc_field proc_field[MAX_FIELDS]
     { "USERNAME", 8, 0, 0, fmt_username },
     { "UID", 6, 1, 0, fmt_uid },
     { "THR", 3, 1, 0, fmt_thr },
-    { "PRI", 3, 1, 0, fmt_pri },
+    { "PRI", 4, 1, 0, fmt_pri },
     { "NICE", 4, 1, 0, fmt_nice },
     { "SIZE", 5, 1, 0, fmt_size },
     { "RES", 5, 1, 0, fmt_res },
--- c.diff ends here ---
